	//     stdout headline (the store path) stays clean.
	if seeded {
		fmt.Fprintf(stderr, "Seeded example skill at %s\n", filepath.Join(store, "example", "SKILL.md"))
	} else {
		fmt.Fprintf(stderr, "Adopted existing store at %s\n", store)
	}
